export declare const ZSH_COMPLETION = "#compdef tack\n\n_tack_routes() {\n  local tack_dir=\"${TACK_HOME:-$HOME/.tack}/routes\"\n  [[ -d \"$tack_dir\" ]] || return\n  local -a routes\n  routes=( \"$tack_dir\"/*.yaml(N:t:r) )\n  (( ${#routes} )) && compadd -a routes\n}\n\n_tack_repo_names() {\n  local repos_file=\"${TACK_HOME:-$HOME/.tack}/repos.yaml\"\n  [[ -f \"$repos_file\" ]] || return\n  local -a names\n  names=( ${(f)\"$(awk '\n    /^[^[:space:]]/ { in_names=0 }\n    /^  names:/ { in_names=1; next }\n    /^  [^[:space:]]/ { in_names=0 }\n    in_names && /^    - / { v=substr($0, 7); gsub(/\"/, \"\", v); print v }\n  ' \"$repos_file\")\"} )\n  (( ${#names} )) && compadd -a names\n}\n\n_tack_tack_ids() {\n  local slug=\"$1\"\n  local tack_dir=\"${TACK_HOME:-$HOME/.tack}/routes\"\n  local route_file=\"$tack_dir/$slug.yaml\"\n  [[ -f \"$route_file\" ]] || return\n  local -a ids descs\n  local id summary\n  while IFS= read -r line; do\n    if [[ \"$line\" =~ '^  - id: (.+)' ]]; then\n      id=\"${match[1]}\"\n    elif [[ -n \"$id\" && \"$line\" =~ '^    summary: (.+)' ]]; then\n      summary=\"${match[1]}\"\n      ids+=(\"$id\")\n      descs+=(\"$id:$summary\")\n      id=\"\"\n    fi\n  done < \"$route_file\"\n  if (( ${#descs} )); then\n    _describe 'tack' descs\n  elif (( ${#ids} )); then\n    compadd -a ids\n  fi\n}\n\n_tack_todo_ids() {\n  local slug=\"$1\" tack_id=\"$2\"\n  local tack_dir=\"${TACK_HOME:-$HOME/.tack}/routes\"\n  local route_file=\"$tack_dir/$slug.yaml\"\n  [[ -f \"$route_file\" ]] || return\n  local -a ids\n  ids=( ${(f)\"$(awk -v tid=\"$tack_id\" '\n    /^  - id: / { current = $3 }\n    current == tid && /^      - id: [ab][0-9]/ { print $3 }\n  ' \"$route_file\")\"} )\n  (( ${#ids} )) && compadd -a ids\n}\n\n_tack_link_urls() {\n  local slug=\"$1\" tack_id=\"$2\"\n  local tack_dir=\"${TACK_HOME:-$HOME/.tack}/routes\"\n  local route_file=\"$tack_dir/$slug.yaml\"\n  [[ -f \"$route_file\" ]] || return\n  local -a urls\n  urls=( ${(f)\"$(awk -v tid=\"$tack_id\" '\n    /^  - id: / { in_tack = ($3 == tid) ? 1 : 0; in_links = 0; next }\n    in_tack && /^    links:/ { in_links = 1; next }\n    in_tack && /^    [a-z]/ { in_links = 0 }\n    in_tack && in_links && /^      url: / { print $2 }\n  ' \"$route_file\")\"} )\n  (( ${#urls} )) && compadd -a urls\n}\n\n_tack_move_src() {\n  local tack_dir=\"${TACK_HOME:-$HOME/.tack}/routes\"\n  [[ -d \"$tack_dir\" ]] || return\n  local cur=\"${words[CURRENT]}\"\n\n  # slug/ \u2192 complete tack IDs only, no trailing slash, no aspect drill-down\n  if [[ \"$cur\" == */* ]]; then\n    local slug=\"${cur%%/*}\"\n    local route_file=\"$tack_dir/$slug.yaml\"\n    [[ -f \"$route_file\" ]] || return\n    local -a tack_ids tack_descs\n    local id summary\n    while IFS= read -r line; do\n      if [[ \"$line\" =~ '^  - id: (.+)' ]]; then\n        id=\"${match[1]}\"\n      elif [[ -n \"$id\" && \"$line\" =~ '^    summary: (.+)' ]]; then\n        summary=\"${match[1]}\"\n        tack_ids+=(\"$slug/$id\")\n        tack_descs+=(\"$slug/$id ($summary)\")\n        id=\"\"\n      fi\n    done < \"$route_file\"\n    (( ${#tack_ids} )) && compadd -l -d tack_descs -a tack_ids\n    return\n  fi\n\n  # no slash \u2192 route slugs with / suffix to continue typing the tack-id\n  local -a slugs\n  slugs=( \"$tack_dir\"/*.yaml(N:t:r) )\n  (( ${#slugs} )) && compadd -S / -q -a slugs\n}\n\n_tack_tree_path() {\n  local tack_dir=\"${TACK_HOME:-$HOME/.tack}/routes\"\n  [[ -d \"$tack_dir\" ]] || return\n  local cur=\"${words[CURRENT]}\"\n  local -a parts\n  parts=(\"${(@s:/:)cur}\")\n  local nparts=${#parts}\n\n  # slug/tack-id/ \u2192 complete aspects\n  if (( nparts >= 3 )) || { (( nparts == 2 )) && [[ \"$cur\" == */*/  ]]; }; then\n    local slug=\"${parts[1]}\"\n    local tack_id=\"${parts[2]}\"\n    local route_file=\"$tack_dir/$slug.yaml\"\n    [[ -f \"$route_file\" ]] || return\n    local prefix=\"$slug/$tack_id/\"\n    local -a aspects\n    # parse which aspects this tack actually has\n    local in_tack=0 has_deliverable=0 has_before=0 has_after=0 has_links=0 has_depends=0\n    while IFS= read -r line; do\n      if [[ \"$line\" =~ '^  - id: (.+)' ]]; then\n        [[ \"${match[1]}\" == \"$tack_id\" ]] && in_tack=1 || { (( in_tack )) && break; }\n      elif (( in_tack )); then\n        [[ \"$line\" =~ '^    deliverable:' ]] && has_deliverable=1\n        [[ \"$line\" =~ '^    before:' ]] && has_before=1\n        [[ \"$line\" =~ '^    after:' ]] && has_after=1\n        [[ \"$line\" =~ '^    links:' ]] && has_links=1\n        [[ \"$line\" =~ '^    depends_on:' ]] && has_depends=1\n      fi\n    done < \"$route_file\"\n    (( has_deliverable )) && aspects+=(\"${prefix}deliverable\")\n    (( has_before )) && aspects+=(\"${prefix}before\")\n    (( has_after )) && aspects+=(\"${prefix}after\")\n    (( has_links )) && aspects+=(\"${prefix}links\")\n    (( has_depends )) && aspects+=(\"${prefix}depends_on\")\n    (( ${#aspects} )) && compadd -Q -a aspects\n    return\n  fi\n\n  # slug/ \u2192 complete tack IDs\n  if [[ \"$cur\" == */* ]]; then\n    local slug=\"${cur%%/*}\"\n    local route_file=\"$tack_dir/$slug.yaml\"\n    [[ -f \"$route_file\" ]] || return\n    local -a tack_ids tack_descs\n    local id summary\n    while IFS= read -r line; do\n      if [[ \"$line\" =~ '^  - id: (.+)' ]]; then\n        id=\"${match[1]}\"\n      elif [[ -n \"$id\" && \"$line\" =~ '^    summary: (.+)' ]]; then\n        summary=\"${match[1]}\"\n        tack_ids+=(\"$slug/$id\")\n        tack_descs+=(\"$slug/$id ($summary)\")\n        id=\"\"\n      fi\n    done < \"$route_file\"\n    (( ${#tack_ids} )) && compadd -S / -q -l -d tack_descs -a tack_ids\n    return\n  fi\n\n  # no slash \u2192 complete route slugs\n  local -a routes slugs descs\n  local slug route_file open total\n  routes=( \"$tack_dir\"/*.yaml(N:t:r) )\n  for slug in \"${routes[@]}\"; do\n    route_file=\"$tack_dir/$slug.yaml\"\n    total=$(grep -c '^  - id: ' \"$route_file\" 2>/dev/null || echo 0)\n    open=$(awk '/^  - id:/{t=1} t && /^    status:/{if($2!=\"done\" && $2!=\"dropped\")c++; t=0} END{print c+0}' \"$route_file\")\n    slugs+=(\"$slug\")\n    descs+=(\"$slug ($open open / $total total)\")\n  done\n  (( ${#slugs} )) && compadd -S / -q -l -d descs -a slugs\n}\n\n_tack() {\n  local -a commands\n  commands=(\n    'init:Create a new route'\n    'status:Show route status'\n    'list:List all routes'\n    'recent:List recently updated routes'\n    'tree:Browse routes and tacks'\n    'add:Add a tack to a route'\n    'start:Start working on a tack'\n    'done:Mark a tack as done'\n    'drop:Drop a tack (mark as dropped, keep in file)'\n    'remove:Delete a tack from a route'\n    'edit:Edit a tack summary'\n    'merge:Merge a tack into another'\n    'move:Move a tack to another route'\n    'deliverable:Set a deliverable on a tack'\n    'before:Add a pre-work todo'\n    'after:Add a post-work todo'\n    'todo:Manage todo items'\n    'depends:Add or remove a tack dependency'\n    'link:Add a link to a tack'\n    'session:Record a session'\n    'find:Find the tack that owns a URL'\n    'pin:Pin a route to the current cwd'\n    'unpin:Clear the cwd pin'\n    'pins:List all pins (or prune stale ones)'\n    'repo:Look up a repo remote by name'\n    'rm:Delete a route'\n    'rename:Rename a route'\n    'group:Set, change, or clear a route group'\n    'export:Dump a backup to stdout (routes + repos + pins)'\n    'import:Merge or restore a backup'\n    'install-cli:Drop a tack wrapper on PATH'\n    'completions:Output shell completion script'\n    'help:Show usage'\n  )\n\n  if (( CURRENT == 2 )); then\n    _describe 'command' commands\n    return\n  fi\n\n  local command=\"${words[2]}\"\n\n  case \"$command\" in\n    init)\n      # tack init <slug> [--group <slug>]\n      case \"$CURRENT\" in\n        3) _message 'slug' ;;\n        *) _arguments '--group[Group slug]:group:_tack_routes' ;;\n      esac\n      ;;\n    status)\n      # tack status [slug] [--json] [--all]\n      # tack status set <slug> <tack-id> <status>\n      case \"$CURRENT\" in\n        3) local -a subcmds; subcmds=('set:Set a tack status with no guards'); _describe 'subcommand' subcmds; _tack_routes; _arguments '--json[Output JSON]' '--all[Include dropped tacks]' ;;\n        4)\n          if [[ \"${words[3]}\" == \"set\" ]]; then\n            _tack_routes\n          else\n            _arguments '--json[Output JSON]' '--all[Include dropped tacks]'\n          fi\n          ;;\n        5)\n          if [[ \"${words[3]}\" == \"set\" ]]; then\n            _tack_tack_ids \"${words[4]}\"\n          fi\n          ;;\n        6)\n          if [[ \"${words[3]}\" == \"set\" ]]; then\n            compadd pending in_progress done blocked dropped\n          fi\n          ;;\n        *) _arguments '--json[Output JSON]' '--all[Include dropped tacks]' ;;\n      esac\n      ;;\n    list)\n      # tack list [--json]\n      _arguments '--json[Output JSON]'\n      ;;\n    tree)\n      # tack tree [path] [-d <depth>] [--json]\n      case \"$CURRENT\" in\n        3) _tack_tree_path; _arguments '-d[Expansion depth (1-3)]:depth:(1 2 3)' '--depth[Expansion depth (1-3)]:depth:(1 2 3)' '--json[Output JSON]' ;;\n        *) _arguments '-d[Expansion depth (1-3)]:depth:(1 2 3)' '--depth[Expansion depth (1-3)]:depth:(1 2 3)' '--json[Output JSON]' ;;\n      esac\n      ;;\n    recent)\n      # tack recent [--count <n>] [--since <date>] [--json]\n      _arguments '--count[Max routes]:count' '--since[Updated since date]:since' '--json[Output JSON]'\n      ;;\n    add)\n      # tack add <slug> <summary> [--depends-on <id,...>] [--deliverable <url>] [--link \"label,url\"]...\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _message 'summary' ;;\n        *) _arguments              '--depends-on[Comma-separated tack IDs]:depends'              '--done[Create the tack already done]'              '--date[Backfill done_at]:date:'              '--deliverable[Set deliverable URL on creation]:url:'              '*--link[Attach a link (label,url); repeatable]:link:' ;;\n      esac\n      ;;\n    start|done|drop)\n      # tack {start|done|drop} <slug> <tack-id>\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _tack_tack_ids \"${words[3]}\" ;;\n      esac\n      ;;\n    remove)\n      # tack remove <slug> <tack-id> [--force]\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _tack_tack_ids \"${words[3]}\" ;;\n        *) _arguments '--force[Strip dependent references]' ;;\n      esac\n      ;;\n    edit)\n      # tack edit <slug> <tack-id> <summary>\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _tack_tack_ids \"${words[3]}\" ;;\n        5) _message 'summary' ;;\n      esac\n      ;;\n    merge)\n      # tack merge <slug> <source-id> <target-id>\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _tack_tack_ids \"${words[3]}\" ;;\n        5) _tack_tack_ids \"${words[3]}\" ;;\n      esac\n      ;;\n    move)\n      # tack move <src-slug>/<tack-id> <dst-slug> [--include-dependents]\n      case \"$CURRENT\" in\n        3) _tack_move_src ;;\n        4) _tack_routes ;;\n        *) _arguments '--include-dependents[Move dependents too]' ;;\n      esac\n      ;;\n    deliverable)\n      # tack deliverable <slug> <tack-id> <url> [--label <text>] [--force]\n      # tack deliverable rm <slug> <tack-id> [--to-link]\n      if [[ \"${words[3]}\" == \"rm\" ]]; then\n        case \"$CURRENT\" in\n          3) _tack_routes ;;\n          4) _tack_routes ;;\n          5) _tack_tack_ids \"${words[4]}\" ;;\n          *) _arguments '--to-link[Demote the deliverable into links]' ;;\n        esac\n      else\n        case \"$CURRENT\" in\n          3) _alternative 'subcommands:subcommand:((rm:\"clear or demote the deliverable\"))' 'routes:route:_tack_routes' ;;\n          4) _tack_tack_ids \"${words[3]}\" ;;\n          5) _message 'url' ;;\n          *) _arguments '--label[Override the derived label]:label:' '--force[Overwrite existing deliverable]' ;;\n        esac\n      fi\n      ;;\n    before|after)\n      # tack {before|after} <slug> <tack-id> <text>\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _tack_tack_ids \"${words[3]}\" ;;\n        5) _message 'text' ;;\n      esac\n      ;;\n    todo)\n      # tack todo {done|rm} <slug> <tack-id> <todo-id>\n      case \"$CURRENT\" in\n        3) local -a subcmds; subcmds=('done:Complete a todo' 'rm:Delete a todo'); _describe 'subcommand' subcmds ;;\n        4) _tack_routes ;;\n        5) _tack_tack_ids \"${words[4]}\" ;;\n        6) _tack_todo_ids \"${words[4]}\" \"${words[5]}\" ;;\n      esac\n      ;;\n    link)\n      # tack link {add|rm} ...\n      case \"$CURRENT\" in\n        3) local -a subcmds; subcmds=('add:Add a link' 'rm:Remove a link'); _describe 'subcommand' subcmds ;;\n        4) _tack_routes ;;\n        5) _tack_tack_ids \"${words[4]}\" ;;\n        *)\n          case \"${words[3]}\" in\n            add)\n              # tack link add <slug> <tack-id> <label> <url>\n              case \"$CURRENT\" in\n                6) _message 'label' ;;\n                7) _message 'url' ;;\n              esac\n              ;;\n            rm)\n              # tack link rm <slug> <tack-id> <url>\n              case \"$CURRENT\" in\n                6) _tack_link_urls \"${words[4]}\" \"${words[5]}\" ;;\n              esac\n              ;;\n          esac\n          ;;\n      esac\n      ;;\n    depends)\n      # tack depends {add|rm} <slug> <tack-id> <dep-id>\n      case \"$CURRENT\" in\n        3) local -a subcmds; subcmds=('add:Add a dependency' 'rm:Remove a dependency'); _describe 'subcommand' subcmds ;;\n        4) _tack_routes ;;\n        5) _tack_tack_ids \"${words[4]}\" ;;\n        6) _tack_tack_ids \"${words[4]}\" ;;\n      esac\n      ;;\n    rename)\n      # tack rename <old-slug> <new-slug>\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _message 'new-slug' ;;\n      esac\n      ;;\n    group)\n      # tack group <slug> [<group>] [--clear]\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        *) _arguments '--clear[Remove the route group]' ;;\n      esac\n      ;;\n    session)\n      # tack session <slug> <session-id> [--tack <tack-id>]\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        4) _message 'session-id' ;;\n        *)\n          if [[ \"${words[CURRENT-1]}\" == \"--tack\" ]]; then\n            _tack_tack_ids \"${words[3]}\"\n          else\n            _arguments '--tack[Bind the session to a tack]:tack-id:'\n          fi\n          ;;\n      esac\n      ;;\n    pin)\n      # tack pin [<slug>]\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n      esac\n      ;;\n    unpin)\n      # tack unpin (no args)\n      ;;\n    pins)\n      # tack pins [prune | --json]\n      case \"$CURRENT\" in\n        3) _alternative 'subcommands:subcommand:((prune:\"remove stale pins\"))' 'options:option:((--json:\"emit JSON\"))' ;;\n      esac\n      ;;\n    repo)\n      # tack repo [<partial>] [--json] | alias <match> <alias> | prune | rm <match>\n      case \"$CURRENT\" in\n        3) _alternative 'subcommands:subcommand:((alias:\"add an alias\" prune:\"drop stale locals\" rebuild:\"backfill from routes + pins\" rm:\"remove a repo\"))' 'repos:repo:_tack_repo_names' 'options:option:((--json:\"emit JSON\"))' ;;\n        4)\n          case \"${words[3]}\" in\n            alias|rm) _tack_repo_names ;;\n          esac\n          ;;\n      esac\n      ;;\n    rm)\n      # tack rm <slug> [--force]\n      case \"$CURRENT\" in\n        3) _tack_routes ;;\n        *) _arguments '--force[Skip confirmation]' ;;\n      esac\n      ;;\n    find)\n      # tack find <url> [--json]\n      case \"$CURRENT\" in\n        3) _message 'url' ;;\n        *) _arguments '--json[Output JSON]' ;;\n      esac\n      ;;\n    export)\n      # tack export [--out-file <path>] [--compress]\n      _arguments '--out-file[Write to a file instead of stdout]:file:_files' '--compress[Gzip the output]'\n      ;;\n    import)\n      # tack import <file> [--merge|--replace] [--dry-run]\n      case \"$CURRENT\" in\n        3) _files ;;\n        *) _arguments '--merge[Combine with local store (default)]' '--replace[Restore this machine wholesale]' '--dry-run[Preview without writing]' ;;\n      esac\n      ;;\n    install-cli)\n      # tack install-cli [--dir <path>]\n      _arguments '--dir[Install directory (default ~/.local/bin)]:dir:_files -/'\n      ;;\n    completions)\n      # tack completions <shell>\n      case \"$CURRENT\" in\n        3) compadd zsh ;;\n      esac\n      ;;\n  esac\n}\n\n_tack \"$@\"\n";
